local redis = require "resty.redis"
local http = require "resty.http"

local function load_plugin_from_redis(plugin_key)
    local red = redis:new()
    red:set_timeouts(1000, 1000, 1000)
    
    local ok, err = red:connect("127.0.0.1", 6379)
    if not ok then
        ngx.log(ngx.ERR, "failed to connect to redis: ", err)
        return nil
    end
    
    local plugin_code, err = red:get(plugin_key)
    if not plugin_code or plugin_code == ngx.null then
        ngx.log(ngx.ERR, "plugin code not found in redis: ", err)
        return nil
    end
    
    red:close()
    
    local func, err = loadstring(plugin_code)
    if not func then
        ngx.log(ngx.ERR, "failed to load plugin code: ", err)
        return nil
    end
    
    return func
end

local function load_plugin_from_header(header_name)
    local plugin_code = ngx.var.headers[header_name]
    if not plugin_code then
        ngx.log(ngx.ERR, "plugin code not found in header: ", header_name)
        return nil
    end
    
    local func, err = loadstring(plugin_code)
    if not func then
        ngx.log(ngx.ERR, "failed to load plugin code from header: ", err)
        return nil
    end
    
    return func
end

local function execute_plugin(plugin_func, ...)
    if not plugin_func then
        return nil, "plugin function is nil"
    end
    
    local ok, result = pcall(plugin_func, ...)
    if not ok then
        return nil, result
    end
    
    return result
end

local function load_and_execute_plugin(source, key_or_header, ...)
    local plugin_func
    
    if source == "redis" then
        plugin_func = load_plugin_from_redis(key_or_header)
    elseif source == "header" then
        plugin_func = load_plugin_from_header(key_or_header)
    else
        return nil, "invalid source. use 'redis' or 'header'"
    end
    
    return execute_plugin(plugin_func, ...)
end

